     4â†’import { useEffect } from "react";
     5â†’import useSWR, { mutate } from "swr";
     6â†’import { StatsCards } from "@/components/dashboard/stats-cards";
     7â†’import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     8â†’import { UnifiedFeed } from "@/components/dashboard/unified-feed";
     9â†’import { DashboardEmptyState } from "@/components/dashboard/empty-state";
    10â†’import { projects as projectsApi } from "@/lib/api/client";
    11â†’
    12â†’const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    13â†’
    14â†’export default function DashboardPage() {
    15â†’  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    16â†’    projectsApi.list()
    17â†’  );
    18â†’
    19â†’  // Listen to SSE events and revalidate dashboard data on new releases
    20â†’  useEffect(() => {
    21â†’    let es: EventSource | null = null;
    22â†’    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    23â†’
    24â†’    function connect() {
    25â†’      try {
    26â†’        es = new EventSource(`${SSE_BASE}/events`);
    27â†’        es.onmessage = () => {
    28â†’          // Revalidate all dashboard SWR keys on any event
    29â†’          mutate((key) => typeof key === "string" && (
    30â†’            key === "stats" ||
    31â†’            key.startsWith("trend-") ||
    32â†’            key === "unified-feed"
    33â†’          ), undefined, { revalidate: true });
    34â†’        };
    35â†’        es.onerror = () => {
    36â†’          es?.close();
    37â†’          retryTimer = setTimeout(connect, 5000);
    38â†’        };
    39â†’      } catch {
    40â†’        retryTimer = setTimeout(connect, 5000);
    41â†’      }
    42â†’    }
    43â†’
    44â†’    connect();
    45â†’    return () => {
    46â†’      es?.close();
    47â†’      if (retryTimer) clearTimeout(retryTimer);
    48â†’    };
    49â†’  }, []);
    50â†’
    51â†’  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    52â†’
    53â†’  return (
    54â†’    <div className="space-y-6">
    55â†’      <h1
    56â†’        style={{
    57â†’          fontFamily: "var(--font-fraunces)",
    58â†’          fontSize: "24px",
    59â†’          fontWeight: 700,
    60â†’          color: "#111113",
    61â†’        }}
    62â†’      >
    63â†’        Dashboard
    64â†’      </h1>
    65â†’
    66â†’      {hasProjects ? (
    67â†’        <>
    68â†’          <StatsCards />
    69â†’          <div className="grid gap-4 lg:grid-cols-2">
    70â†’            <ReleaseTrendChart />
    71â†’            <UnifiedFeed />
    72â†’          </div>
    73â†’        </>
    74â†’      ) : isLoading ? (
    75â†’        <div
    76â†’          className="py-16 text-center"
    77â†’          style={{
    78â†’            fontFamily: "var(--font-dm-sans)",
    79â†’            fontSize: "13px",
    80â†’            color: "#6b7280",
    81â†’          }}
    82â†’        >
    83â†’          Loading...
    84â†’        </div>
    85â†’      ) : (
    86â†’        <DashboardEmptyState />
    87â†’      )}
    88â†’    </div>
    89â†’  );
    90â†’}
