    22â†’const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    23â†’  critical: { bg: "#dc2626", text: "#ffffff" },
    24â†’  high: { bg: "#f97316", text: "#ffffff" },
    25â†’  medium: { bg: "#f59e0b", text: "#ffffff" },
