    29â†’/* ---------- Project Card Logo ---------- */
    30â†’
    31â†’function ProjectCardLogo({ projectId, name }: { projectId: string; name: string }) {
    32â†’  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
    33â†’    sourcesApi.listByProject(projectId)
    34â†’  );
    35â†’  return <ProjectLogo name={name} sources={data?.data} size={40} />;
    36â†’}
    37â†’
    38â†’/* ---------- Overflow Flow ---------- */
    39â†’
    40â†’const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    41â†’const MAX_LINES = 2;
    42â†’const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    43â†’
    44â†’function FlowSection({
    45â†’  label,
    46â†’  moreHref,
    47â†’  children,
    48â†’}: {
    49â†’  label: string;
    50â†’  moreHref: string;
    51â†’  children: React.ReactNode;
    52â†’}) {
    53â†’  const measureRef = useRef<HTMLDivElement>(null);
    54â†’  const moreRef = useRef<HTMLSpanElement>(null);
    55â†’  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    56â†’
    57â†’  const items = React.Children.toArray(children);
    58â†’
    59â†’  const measure = useCallback(() => {
    60â†’    const el = measureRef.current;
    61â†’    if (!el) return;
    62â†’    const nodes = el.children;
    63â†’    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "moreâ€¦" span (last)
    64â†’    // Check if everything fits without overflow
    65â†’    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    66â†’      setVisibleCount(items.length);
    67â†’      return;
    68â†’    }
    69â†’    // Measure actual "moreâ€¦" link width
    70â†’    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    71â†’    const containerWidth = el.offsetWidth;
    72â†’    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    73â†’    let lastFitting = 0;
    74â†’    for (let i = 1; i <= itemNodeCount; i++) {
    75â†’      const node = nodes[i] as HTMLElement;
    76â†’      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    77â†’      lastFitting = i;
    78â†’    }
    79â†’    // Second pass: walk backward from lastFitting until "moreâ€¦" fits after the item
    80â†’    let count = lastFitting;
    81â†’    while (count > 1) {
    82â†’      const node = nodes[count] as HTMLElement;
    83â†’      const nodeBottom = node.offsetTop + node.offsetHeight;
    84â†’      // If this item is on line 1, "moreâ€¦" can always wrap to line 2 â€” we're fine
    85â†’      if (nodeBottom <= LINE_HEIGHT) break;
    86â†’      // Item is on line 2 â€” check if "moreâ€¦" fits after it on the same line
    87â†’      const nodeRight = node.offsetLeft + node.offsetWidth;
    88â†’      if (nodeRight + moreWidth <= containerWidth) break;
    89â†’      count--;
    90â†’    }
    91â†’    setVisibleCount(Math.max(1, count));
    92â†’  }, [items.length]);
    93â†’
    94â†’  useEffect(() => {
    95â†’    const raf = requestAnimationFrame(measure);
    96â†’    const obs = new ResizeObserver(measure);
    97â†’    if (measureRef.current) obs.observe(measureRef.current);
    98â†’    return () => {
    99â†’      cancelAnimationFrame(raf);
   100â†’      obs.disconnect();
   101â†’    };
   102â†’  }, [measure, items.length]);
   103â†’
   104â†’  const hasOverflow = visibleCount !== null && visibleCount < items.length;
   105â†’  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   106â†’
   107â†’  return (
   108â†’    <div className="relative">
   109â†’      {/* Hidden measurer â€” renders all items to find cutoff */}
   110â†’      <div
   111â†’        ref={measureRef}
   112â†’        className="text-[13px] leading-7"
   113â†’        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   114â†’        aria-hidden="true"
   115â†’      >
   116â†’        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   117â†’          {label}:
   118â†’        </span>
   119â†’        {items}
   120â†’        {/* Hidden "moreâ€¦" to measure its actual width */}
   121â†’        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   122â†’          moreâ€¦
   123â†’        </span>
   124â†’      </div>
   125â†’      {/* Visible section */}
   126â†’      <div className="text-[13px] leading-7">
   127â†’        <span
   128â†’          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   129â†’          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   130â†’        >
   131â†’          {label}:
   132â†’        </span>
   133â†’        {displayed}
   134â†’        {hasOverflow && (
   135â†’          <Link
   136â†’            href={moreHref}
   137â†’            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   138â†’            style={{ color: "#e8601a" }}
   139â†’          >
   140â†’            moreâ€¦
   141â†’          </Link>
   142â†’        )}
   143â†’      </div>
   144â†’    </div>
   145â†’  );
   146â†’}
