   204â†’        </div>
   205â†’      </div>
   206â†’
   207â†’      {/* Sources chips */}
   208â†’      <div className="flex flex-wrap items-center gap-1.5 mb-3">
   209â†’        <span
   210â†’          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-0.5"
   211â†’          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   212â†’        >
   213â†’          Sources:
   214â†’        </span>
   215â†’        {sources.map((source) => (
   216â†’          <button
