   237â†’            )}
   238â†’            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0" style={{ color: "#9ca3af", opacity: 0.5 }} />
   239â†’          </button>
   240â†’        ))}
   241â†’        <button
   242â†’          onClick={() => setSourceCreateOpen(true)}
   243â†’          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-[#f3f3f1]"
