   281â†’                <span
   282â†’                  className="text-[11px] ml-1"
   283â†’                  style={{ color: r.excluded ? "#dcdcda" : "#c4c4c0" }}
   284â†’                >
   285â†’                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
   286â†’                </span>
   287â†’              </span>
   288â†’            );
   289â†’          })}
   290â†’        </FlowSection>
   291â†’      )}
   292â†’
   293â†’      {/* Semantic releases */}
   294â†’      {srItems.length > 0 && (
   295â†’        <FlowSection label="Semantic Releases" moreHref={`/semantic-releases?project=${project.id}`}>
   296â†’          {srItems.map((sr) => {
   297â†’            const urgencyStyle = sr.report?.urgency
   298â†’              ? URGENCY_COLORS[sr.report.urgency.toLowerCase()]
   299â†’              : undefined;
   300â†’            return (
   301â†’              <span key={sr.id} className="inline-flex items-center gap-1.5 mr-2.5">
