   305â†’                  style={{
   306â†’                    backgroundColor: "#eff6ff",
   307â†’                    fontFamily: "'JetBrains Mono', monospace",
   308â†’                    color: "#1d4ed8",
   309â†’                  }}
   310â†’                >
   311â†’                  {sr.version}
   312â†’                </Link>
   313â†’                {urgencyStyle && (
   314â†’                  <span
   315â†’                    className="rounded px-1.5 py-0.5 text-[10px] uppercase font-bold tracking-wide leading-none"
   316â†’                    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
   317â†’                  >
   318â†’                    {sr.report?.urgency}
   319â†’                  </span>
   320â†’                )}
   321â†’              </span>
   322â†’            );
   323â†’          })}
   324â†’        </FlowSection>
   325â†’      )}
   326â†’
   327â†’      {/* Add Source dialog */}
   328â†’      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
   329â†’        <DialogContent className="sm:max-w-lg">
   330â†’          <DialogHeader>
   331â†’            <DialogTitle>Add Source</DialogTitle>
   332â†’          </DialogHeader>
   333â†’          <SourceForm
   334â†’            title="Add Source"
   335â†’            projectId={project.id}
   336â†’            onSubmit={async (input) => {
   337â†’              const res = await sourcesApi.create(project.id, input);
   338â†’              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
   339â†’            }}
   340â†’            onSuccess={() => {
   341â†’              setSourceCreateOpen(false);
   342â†’              mutateSources();
   343â†’            }}
   344â†’            onCancel={() => setSourceCreateOpen(false)}
   345â†’          />
   346â†’        </DialogContent>
   347â†’      </Dialog>
   348â†’
   349â†’      {/* Edit Source dialog */}
   350â†’      <Dialog
   351â†’        open={!!editingSource}
