   365â†’              }}
   366â†’              onSuccess={() => {
   367â†’                setEditingSource(null);
   368â†’                mutateSources();
   369â†’              }}
   370â†’              onCancel={() => setEditingSource(null)}
   371â†’            />
   372â†’          )}
   373â†’        </DialogContent>
   374â†’      </Dialog>
   375â†’    </div>
   376â†’  );
   377â†’}
