   381â†’function ProjectCompactRow({ project }: { project: Project }) {
   382â†’  const router = useRouter();
   383â†’  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
   384â†’    releasesApi.listByProject(project.id, 1, 5, true)
   385â†’  );
   386â†’  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
