   388â†’  );
   389â†’  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
   390â†’    srApi.list(project.id, 1, 3)
   391â†’  );
   392â†’
   393â†’  const releases = relData?.data ?? [];
   394â†’  const sources = srcData?.data ?? [];
   395â†’  const srItems = srData?.data ?? [];
