    32â†’export function formatInterval(seconds: number): string {
    33â†’  if (seconds === 3600) return "Hourly";
    34â†’  if (seconds === 86400) return "Daily";
    35â†’  if (seconds === 604800) return "Weekly";
    36â†’  if (seconds === 2592000) return "Monthly";
    37â†’  if (seconds < 60) return `${seconds}s`;
    38â†’  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    39â†’  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)}h`;
    40â†’  return `${(seconds / 86400).toFixed(1)}d`;
    41â†’}
