    10â†’// Service orchestrates ingestion sources and persists results.
    11â†’type Service struct {
    12â†’	store ReleaseStore
    13â†’}
    14â†’
    15â†’func NewService(store ReleaseStore) *Service {
    16â†’	return &Service{store: store}
