    18â†’
    19â†’// ProcessResults persists raw ingestion results via the store.
    20â†’// Duplicate releases (unique constraint violations) are logged and skipped, not fatal.
    21â†’func (s *Service) ProcessResults(ctx context.Context, sourceID string, sourceName string, results []IngestionResult) error {
    22â†’	for _, r := range results {
    23â†’		if err := s.store.IngestRelease(ctx, sourceID, &r); err != nil {
    24â†’			if isUniqueViolation(err) {
    25â†’				slog.Debug("duplicate release, skipping", "version", r.RawVersion)
    26â†’				continue
    27â†’			}
    28â†’			return fmt.Errorf("ingest %s: %w", r.RawVersion, err)
    29â†’		}
    30â†’		slog.Info("ingested release", "source", sourceName, "version", r.RawVersion)
    31â†’	}
    32â†’	return nil
    33â†’}
    34â†’
    35â†’// isUniqueViolation checks if the error is a PostgreSQL unique constraint violation.
    36â†’// pgx wraps the PG error; we check for the SQLSTATE code 23505.
    37â†’func isUniqueViolation(err error) bool {
    38â†’	return strings.Contains(err.Error(), "23505") ||
