    11â†’type Middleware func(http.Handler) http.Handler
    12â†’
    13â†’func Chain(mws ...Middleware) Middleware {
    14â†’	return func(final http.Handler) http.Handler {
    15â†’		for i := len(mws) - 1; i >= 0; i-- {
    16â†’			final = mws[i](final)
    17â†’		}
    18â†’		return final
    19â†’	}
    20â†’}
    21â†’
    22â†’func RequestID(next http.Handler) http.Handler {
    23â†’	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    24â†’		id := uuid.New().String()
    25â†’		w.Header().Set("X-Request-ID", id)
    26â†’		next.ServeHTTP(w, r.WithContext(withRequestID(r.Context(), id)))
    27â†’	})
    28â†’}
    29â†’
    30â†’func Logger(next http.Handler) http.Handler {
    31â†’	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    32â†’		start := time.Now()
    33â†’		sw := &statusWriter{ResponseWriter: w, status: http.StatusOK}
    34â†’		next.ServeHTTP(sw, r)
    35â†’		slog.Info("request",
    36â†’			"request_id", getRequestID(r.Context()),
    37â†’			"method", r.Method,
    38â†’			"path", r.URL.Path,
    39â†’			"status", sw.status,
    40â†’			"duration_ms", time.Since(start).Milliseconds(),
    41â†’		)
    42â†’	})
    43â†’}
