    33â†’func (s *DockerHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    34â†’	url := fmt.Sprintf("%s/v2/repositories/%s/tags/?page_size=25&ordering=last_updated",
    35â†’		s.baseURL, s.repository)
    36â†’
    37â†’	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    38â†’	if err != nil {
    39â†’		return nil, fmt.Errorf("create request: %w", err)
    40â†’	}
    41â†’
    42â†’	resp, err := s.client.Do(req)
    43â†’	if err != nil {
    44â†’		return nil, fmt.Errorf("fetch tags: %w", err)
    45â†’	}
    46â†’	defer resp.Body.Close()
    47â†’
    48â†’	if resp.StatusCode != http.StatusOK {
    49â†’		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
    50â†’	}
    51â†’
    52â†’	var body struct {
    53â†’		Results []struct {
    54â†’			Name        string `json:"name"`
    55â†’			LastUpdated string `json:"last_updated"`
    56â†’		} `json:"results"`
    57â†’	}
    58â†’	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
    59â†’		return nil, fmt.Errorf("decode response: %w", err)
    60â†’	}
    61â†’
    62â†’	results := make([]IngestionResult, 0, len(body.Results))
    63â†’	for _, tag := range body.Results {
    64â†’		ts, _ := time.Parse(time.RFC3339Nano, tag.LastUpdated)
    65â†’		results = append(results, IngestionResult{
