Different patterns for different parameter types:

```go
// Path parameters: r.PathValue("paramName")
func (h *SourcesHandler) Get(w http.ResponseWriter, r *http.Request) {
    id := r.PathValue("id")
    if id == "" {
        RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
        return
    }
    // ... continue
}

// Nested path params
func (h *SourcesHandler) List(w http.ResponseWriter, r *http.Request) {
    projectID := r.PathValue("projectId")  // From route: /projects/{projectId}/sources
    if projectID == "" {
        RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
        return
    }
    // ... continue
}

// Query parameters: r.URL.Query().Get("name")
func (h *HealthHandler) Trend(w http.ResponseWriter, r *http.Request) {
    granularity := r.URL.Query().Get("granularity")
    if granularity == "" {
        granularity = "daily"
    }

    days := 7
    if d := r.URL.Query().Get("days"); d != "" {
        parsed, err := strconv.Atoi(d)
        if err != nil || parsed < 1 || parsed > 365 {
            RespondError(w, r, http.StatusBadRequest, "invalid_days", "days must be an integer between 1 and 365")
            return
        }
        days = parsed
    }
    // ... continue
}

// Standard pagination helper
page, perPage := ParsePagination(r)  // Reads "page" and "per_page" query params
