package api

import (
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"testing"
)

func TestDiscoverGitHub(t *testing.T) {
	// Mock GitHub Search API responding with one repo item.
	mockGH := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Path != "/search/repositories" {
			http.NotFound(w, r)
			return
		}
		w.Header().Set("Content-Type", "application/json")
		fmt.Fprint(w, `{
			"total_count": 1,
			"items": [{
				"name": "kubernetes",
				"full_name": "kubernetes/kubernetes",
				"description": "Production-Grade Container Scheduling and Management",
				"stargazers_count": 100000,
				"language": "Go",
				"html_url": "https://github.com/kubernetes/kubernetes",
				"owner": {
					"avatar_url": "https://avatars.githubusercontent.com/u/13629408"
				}
			}]
		}`)
	}))
	defer mockGH.Close()

	h := NewDiscoverHandler(mockGH.Client(), mockGH.URL, "")

	mux := http.NewServeMux()
	mux.HandleFunc("GET /discover/github", h.GitHub)

	w := httptest.NewRecorder()
	r := httptest.NewRequest(http.MethodGet, "/discover/github?q=kubernetes", nil)
	mux.ServeHTTP(w, r)

	if w.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d", w.Code)
	}

	var got struct {
		Data []DiscoverItem `json:"data"`
	}
	if err := json.NewDecoder(w.Body).Decode(&got); err != nil {
		t.Fatalf("decode: %v", err)
	}
	if len(got.Data) != 1 {
		t.Fatalf("expected 1 item, got %d", len(got.Data))
	}
	item := got.Data[0]
	if item.FullName != "kubernetes/kubernetes" {
		t.Fatalf("expected full_name=kubernetes/kubernetes, got %s", item.FullName)
	}
	if item.Stars != 100000 {
		t.Fatalf("expected stars=100000, got %d", item.Stars)
	}
	if item.Provider != "github" {
		t.Fatalf("expected provider=github, got %s", item.Provider)
	}
}

package api

import (
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"
)

const discoverCacheTTL = 1 * time.Hour

// DiscoverItem represents a single repository/image result from a discovery search.
type DiscoverItem struct {
	Name        string `json:"name"`
	FullName    string `json:"full_name"`
	Description string `json:"description"`
	Stars       int    `json:"stars"`
	Language    string `json:"language,omitempty"`
	URL         string `json:"url"`
	AvatarURL   string `json:"avatar_url,omitempty"`
	Provider    string `json:"provider"`
}

type cachedResult struct {
	items     []DiscoverItem
	fetchedAt time.Time
}

// DiscoverHandler implements HTTP handlers for the /discover resource.
type DiscoverHandler struct {
	client       *http.Client
	githubURL    string
	dockerHubURL string
	mu           sync.Mutex
	cache        map[string]cachedResult
}

// NewDiscoverHandler returns a new DiscoverHandler. Empty URL strings default
// to the real GitHub / Docker Hub API base URLs.
func NewDiscoverHandler(client *http.Client, githubURL, dockerHubURL string) *DiscoverHandler {
	if githubURL == "" {
		githubURL = "https://api.github.com"
	}
	if dockerHubURL == "" {
		dockerHubURL = "https://hub.docker.com"
	}
	return &DiscoverHandler{
		client:       client,
		githubURL:    githubURL,
		dockerHubURL: dockerHubURL,
		cache:        make(map[string]cachedResult),
	}
}

func (h *DiscoverHandler) getCached(key string) ([]DiscoverItem, bool) {
	h.mu.Lock()
	defer h.mu.Unlock()
	c, ok := h.cache[key]
	if !ok || time.Since(c.fetchedAt) > discoverCacheTTL {
		return nil, false
	}
	return c.items, true
}

func (h *DiscoverHandler) setCache(key string, items []DiscoverItem) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.cache[key] = cachedResult{items: items, fetchedAt: time.Now()}
}

// GitHub handles GET /discover/github â€” searches GitHub repositories.
func (h *DiscoverHandler) GitHub(w http.ResponseWriter, r *http.Request) {
	q := r.URL.Query().Get("q")
	language := r.URL.Query().Get("language")

	cacheKey := fmt.Sprintf("github:%s:%s", q, language)
	if items, ok := h.getCached(cacheKey); ok {
		RespondJSON(w, r, http.StatusOK, items)
		return
	}

	searchQ := q
	if language != "" {
		searchQ = fmt.Sprintf("%s language:%s", q, language)
	}

	url := fmt.Sprintf("%s/search/repositories?q=%s&sort=stars&order=desc&per_page=25", h.githubURL, searchQ)
	resp, err := h.client.Get(url)
	if err != nil {
		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach GitHub API")
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("GitHub API returned %d", resp.StatusCode))
		return
	}

	var ghResp struct {
		Items []struct {
			Name        string `json:"name"`
			FullName    string `json:"full_name"`
			Description string `json:"description"`
			Stars       int    `json:"stargazers_count"`
			Language    string `json:"language"`
			HTMLURL     string `json:"html_url"`
			Owner       struct {
				AvatarURL string `json:"avatar_url"`
			} `json:"owner"`
		} `json:"items"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&ghResp); err != nil {
		RespondError(w, r, http.StatusInternalServerError, "decode_error", "failed to parse GitHub response")
		return
	}

	items := make([]DiscoverItem, 0, len(ghResp.Items))
	for _, repo := range ghResp.Items {
		items = append(items, DiscoverItem{
			Name:        repo.Name,
			FullName:    repo.FullName,
			Description: repo.Description,
			Stars:       repo.Stars,
			Language:    repo.Language,
			URL:         repo.HTMLURL,
			AvatarURL:   repo.Owner.AvatarURL,
			Provider:    "github",
		})
	}

	h.setCache(cacheKey, items)
	RespondJSON(w, r, http.StatusOK, items)
}

// DockerHub handles GET /discover/dockerhub â€” searches Docker Hub repositories.
func (h *DiscoverHandler) DockerHub(w http.ResponseWriter, r *http.Request) {
	q := r.URL.Query().Get("q")
	if q == "" {
		q = "nginx"
	}

	cacheKey := fmt.Sprintf("dockerhub:%s", q)
	if items, ok := h.getCached(cacheKey); ok {
		RespondJSON(w, r, http.StatusOK, items)
		return
	}

	url := fmt.Sprintf("%s/v2/search/repositories/?query=%s&page_size=25", h.dockerHubURL, q)
	resp, err := h.client.Get(url)
	if err != nil {
		RespondError(w, r, http.StatusBadGateway, "upstream_error", "failed to reach Docker Hub API")
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		RespondError(w, r, http.StatusBadGateway, "upstream_error", fmt.Sprintf("Docker Hub API returned %d", resp.StatusCode))
		return
	}

	var dhResp struct {
		Results []struct {
			RepoName         string `json:"repo_name"`
			ShortDescription string `json:"short_description"`
			StarCount        int    `json:"star_count"`
			IsOfficial       bool   `json:"is_official"`
		} `json:"results"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&dhResp); err != nil {
		RespondError(w, r, http.StatusInternalServerError, "decode_error", "failed to parse Docker Hub response")
		return
	}

	items := make([]DiscoverItem, 0, len(dhResp.Results))
	for _, repo := range dhResp.Results {
		name := repo.RepoName
		fullName := repo.RepoName
		if repo.IsOfficial {
			fullName = "library/" + repo.RepoName
		}
		items = append(items, DiscoverItem{
			Name:        name,
			FullName:    fullName,
			Description: repo.ShortDescription,
			Stars:       repo.StarCount,
			URL:         fmt.Sprintf("https://hub.docker.com/_/%s", repo.RepoName),
			Provider:    "dockerhub",
		})
	}

	h.setCache(cacheKey, items)
	RespondJSON(w, r, http.StatusOK, items)
}

