		fmt.Fprint(w, `{
			"results": [{
				"repo_name": "nginx",
				"short_description": "Official NGINX image",
				"star_count": 19000,
				"is_official": true
			}]
		}`)
	}))
	defer mockDH.Close()

	h := NewDiscoverHandler(mockDH.Client(), "", mockDH.URL)

	mux := http.NewServeMux()
	mux.HandleFunc("GET /discover/dockerhub", h.DockerHub)

